# Phytron MCC-1 MINI-W-ETH StreamDevice protocol
#
# Important commissioning notes:
# - TCP framing is verified: STX=0x02, ETX=0x03
# - Verified observed request frame bytes: 02 30 58 50 32 30 52 03
#   ASCII inside frame: 0XP20R
# - Verified observed response example: 02 06 31 30 30 03
# - MCC-1 address handling is critical:
#   * old non-working case used address 1
#   * observed working case used address 0
# - The payloads below use address '0' as the current working candidate.
#   If your controller is configured differently, adjust the address byte in
#   the payload body during commissioning.
# - Only the framed style and the getPosition payload candidate are partially
#   evidenced. All other command payloads are placeholders and must be checked
#   against captures or vendor documentation.

Terminator = "";
ReplyTimeout = 1000;
ReadTimeout = 1000;
WriteTimeout = 1000;
ExtraInput = Ignore;

# Common parser note:
# Response parsing is only partially verified.
# Observed reply example suggests:
#   STX + one status/control byte + ASCII integer + ETX
# Therefore the parser below skips one byte after STX and reads an integer.

getPosition {
    # Verified framing, partially evidenced payload candidate.
    # Verified TX bytes seen on working system:
    #   02 30 58 50 32 30 52 03
    # This corresponds to address '0'. Change the leading address byte if needed.
    out "\x02" "0XP20R" "\x03";
    in  "\x02%*c%d\x03";
}

getSpeed {
    # Placeholder payload.
    # Framing style is verified, but command bytes are NOT confirmed.
    # Address handling must be checked during commissioning.
    out "\x02" "0XV20R" "\x03";
    in  "\x02%*c%d\x03";
}

movePlus {
    # Placeholder payload.
    # Framing style is verified, but command bytes are NOT confirmed.
    # Address handling must be checked during commissioning.
    out "\x02" "0XP21R" "\x03";
    @init { }
}

moveMinus {
    # Placeholder payload.
    # Framing style is verified, but command bytes are NOT confirmed.
    # Address handling must be checked during commissioning.
    out "\x02" "0XP22R" "\x03";
    @init { }
}

stopMotion {
    # Placeholder payload.
    # Framing style is verified, but command bytes are NOT confirmed.
    # Address handling must be checked during commissioning.
    out "\x02" "0XH" "\x03";
    @init { }
}
